31	const basePremiums: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const PROCESSING_FEE = 5;
41	
42	export function runScenario(scenario: Scenario): ScenarioResult {
43	  const results = scenario.steps.map((step) => {
44	    const basePremium = step.items.reduce(
45	      (sum, item) => sum + basePremiums[item.type],
46	      0,
47	    );
48	    return { premium: basePremium + PROCESSING_FEE };
49	  });
50	  return { results };
51	}
